const data = $input.first().json;
const msgs = data.messages || [];
const msg = [...msgs].reverse().find(m => m.status !== 'new') ?? msgs[msgs.length - 1];
if (!msg) throw new Error('No messages found in response');
const sellerId = String($('Execute Workflow Trigger').first().json.body.user_id);
const resources = msg.message_resources ?? [];
const packRes = resources.find(r => r.name === 'packs');
const orderRes = resources.find(r => r.name === 'orders');
const packId = packRes?.id ?? null;
const orderId = orderRes?.id ?? packId;
return {
  id: msg.id,
  text: (msg.text ?? '').trim(),
  from: msg.from,
  to: msg.to,
  status: msg.status,
  message_type: String(msg.from?.user_id) === sellerId ? 'seller_to_buyer' : 'buyer_to_seller',
  pack_id: packId,
  order_id: orderId,
  conversation_status: data.conversation_status,
  message_resources: resources
};

const acct = $('get_account_details').first().json;
const msg  = $('normalize_message').first().json;
const API  = 'https://w1206-app.site';
const TOKEN = 'TSL8r4ctWYzXJF9fiAS1Z8RV';
const packId    = String(msg.pack_id || msg.order_id || '');
const inboxId   = String(acct.meli_inbox_id);
const accountId = acct.chatwoot_account_id;

const prev = $input.first().json;
const contactId = prev.payload?.contact?.id
                || prev.payload?.[0]?.id
                || prev.id;
if (!contactId) throw new Error('No contact_id: ' + JSON.stringify(prev));

async function apiGet(path) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'GET',
      url: `${API}${path}`,
      headers: { api_access_token: TOKEN },
      returnFullResponse: false,
    });
    return r;
  } catch (e) {
    return null;
  }
}

async function apiPost(path, body) {
  return await this.helpers.httpRequest({
    method: 'POST',
    url: `${API}${path}`,
    headers: { api_access_token: TOKEN, 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  });
}

const data = await apiGet.call(this, `/api/v1/accounts/${accountId}/contacts/${contactId}/conversations`);
const convs = data?.payload || [];
const existing = convs.find(c => {
  const attrs = c.additional_attributes || {};
  return (
    String(c.inbox_id) === inboxId &&
    (String(c.meta?.source_id) === packId ||
     String(attrs.pack_id) === packId ||
     String(attrs.order_id) === String(msg.order_id || ''))
  );
});

if (existing) {
  if (existing.status === 'resolved' || existing.status === 'snoozed') {
    await apiPost.call(this, `/api/v1/accounts/${accountId}/conversations/${existing.id}/toggle_status`, { status: 'open' });
  }
  return { id: existing.id, _reused: true };
}

const created = await apiPost.call(this, `/api/v1/accounts/${accountId}/conversations`, {
  source_id:  packId,
  contact_id: contactId,
  inbox_id:   acct.meli_inbox_id,
  team_id:    acct.meli_team_id,
  status: 'open',
  additional_attributes: {
    type: 'post-venta',
    order_id: String(msg.order_id || ''),
    pack_id: packId
  }
});
return { id: created.id, _reused: false };

function getSafe(n) { try { return $(n).first().json; } catch(e) { return {}; } }

async function safeFetch(url, headers) {
  try {
    const r = await fetch(url, { method: 'GET', headers });
    if (!r.ok) return null;
    return await r.json();
  } catch(e) { return null; }
}

const account     = getSafe('get_account_details');
const msgDetails  = getSafe('normalize_message');
const ragResult   = getSafe('rag_search');
const convDetails = getSafe('get_or_create_conversation');
const token       = account.access_token;

const orderId = msgDetails.order_id;
let order    = null;
let shipment = null;

if (orderId && token) {
  order = await safeFetch(
    `https://api.mercadolibre.com/orders/${orderId}`,
    { Authorization: `Bearer ${token}` }
  );
  if (order?.shipping?.id) {
    shipment = await safeFetch(
      `https://api.mercadolibre.com/shipments/${order.shipping.id}`,
      { Authorization: `Bearer ${token}` }
    );
  }
}

// Fetch últimos 8 mensajes para contexto de conversación
const histData = await safeFetch(
  `https://w1206-app.site/api/v1/accounts/${account.chatwoot_account_id}/conversations/${convDetails.id}/messages`,
  { api_access_token: 'TSL8r4ctWYzXJF9fiAS1Z8RV' }
);
const histMsgs = (histData?.payload || []).filter(m => !m.private && m.content);
const history = histMsgs.slice(-8).map(m =>
  `${m.message_type === 0 ? 'Cliente' : 'Vendedor'}: ${m.content}`
).join('\n');

const orderCtx = order
  ? `ID: ${order.id} | Estado: ${order.status} | Total: ${order.currency_id} ${order.total_amount} | Productos: ${(order.order_items||[]).map(i=>i.item?.title).join(', ')}`
  : '(Sin datos de pedido)';

const shipCtx = shipment
  ? `ID: ${shipment.id} | Estado: ${shipment.status} | Tracking: ${shipment.tracking_number||'N/A'} | Fecha estimada: ${shipment.estimated_handling_limit?.date || shipment.estimated_delivery_time?.date || 'N/A'}`
  : '(Sin datos de envío)';

return {
  message:               msgDetails.text || '',
  conversation_id:       convDetails.id,
  account_id:            account.chatwoot_account_id,
  ml_user_id:            $('Execute Workflow Trigger').first().json.body.user_id,
  buyer_user_id:         String(msgDetails.from?.user_id || ''),
  pack_id:               msgDetails.pack_id,
  order_context:         orderCtx,
  shipment_context:      shipCtx,
  rag_context:           ragResult.context || '',
  conversation_history:  history,
  prompts:               account.prompts || {},
  pv_ia:                 (() => { try { const r = account.pv_ia; return (typeof r === 'string') ? JSON.parse(r) : (r || {}); } catch(e) { return {}; } })()
};

